CREATE CACHED TABLE "PUBLIC"."USERS"(
    "ID" UUID NOT NULL,
    "USERNAME" CHARACTER VARYING(50),
    "CREATED_AT" TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,
    "ROLE_ID" INTEGER
);              
ALTER TABLE "PUBLIC"."USERS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_4D" PRIMARY KEY("ID");       
-- 0 +/- SELECT COUNT(*) FROM PUBLIC.USERS;   
ALTER TABLE "PUBLIC"."ROLES" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_4A" UNIQUE NULLS DISTINCT ("NAME");          
ALTER TABLE "PUBLIC"."USERS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_4D4" FOREIGN KEY("ROLE_ID") REFERENCES "PUBLIC"."ROLES"("ID") NOCHECK;       

-- Rooms and amenities
CREATE CACHED TABLE IF NOT EXISTS rooms (
    id UUID NOT NULL,
    num_of_beds INTEGER,
    size_in_sqr_m INTEGER,
    price_per_night DECIMAL,
    distance_from_city_center DECIMAL,
    distance_from_beach DECIMAL,
    room_number INTEGER
);
ALTER TABLE rooms ADD CONSTRAINT pk_rooms PRIMARY KEY (id);

CREATE CACHED TABLE IF NOT EXISTS amenities (
    id INTEGER GENERATED BY DEFAULT AS IDENTITY START WITH 1 NOT NULL,
    name VARCHAR(50) NOT NULL
);
ALTER TABLE amenities ADD CONSTRAINT pk_amenities PRIMARY KEY (id);
ALTER TABLE amenities ADD CONSTRAINT uq_amenities_name UNIQUE (name);

CREATE CACHED TABLE IF NOT EXISTS room_amenities (
    room_id UUID NOT NULL,
    amenity_id INTEGER NOT NULL
);
ALTER TABLE room_amenities ADD CONSTRAINT fk_room_amenities_room FOREIGN KEY (room_id) REFERENCES rooms(id) ON DELETE CASCADE;
ALTER TABLE room_amenities ADD CONSTRAINT fk_room_amenities_amenity FOREIGN KEY (amenity_id) REFERENCES amenities(id) ON DELETE CASCADE;

-- Insert default amenities
INSERT INTO amenities(name) SELECT * FROM (VALUES ('GYM'),('WIFI'),('POOL'),('PARKING'),('SPA'),('BREAKFAST')) AS t(name) WHERE NOT EXISTS (SELECT 1 FROM amenities);

